    color: '#ff6e40',
  },
  btnDisabled: {
    opacity: 0.4,
    cursor: 'not-allowed',
  },
  error: {
    padding: '6px 10px',
    background: '#4a1e1e',
    color: '#f48771',
    fontSize: 12,
    borderBottom: '1px solid #6e3333',
    flexShrink: 0,
  },
  editorContainer: {
