import { useCallback, useEffect, useRef, useState } from 'react';
import { IDB_NAME, IDB_STORE, IDB_VERSION } from './constants';

function openDB(): Promise<IDBDatabase> {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(IDB_NAME, IDB_VERSION);
    request.onupgradeneeded = () => {
      const db = request.result;
      if (!db.objectStoreNames.contains(IDB_STORE)) {
        db.createObjectStore(IDB_STORE);
      }
    };
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
}

function idbGet(db: IDBDatabase, key: string): Promise<string | undefined> {
  return new Promise((resolve, reject) => {
    const tx = db.transaction(IDB_STORE, 'readonly');
    const store = tx.objectStore(IDB_STORE);
    const req = store.get(key);
    req.onsuccess = () => resolve(req.result as string | undefined);
    req.onerror = () => reject(req.error);
  });
}

function idbPut(db: IDBDatabase, key: string, value: string): Promise<void> {
  return new Promise((resolve, reject) => {
    const tx = db.transaction(IDB_STORE, 'readwrite');
    const store = tx.objectStore(IDB_STORE);
    const req = store.put(value, key);
    req.onsuccess = () => resolve();
    req.onerror = () => reject(req.error);
  });
}

function idbDelete(db: IDBDatabase, key: string): Promise<void> {
  return new Promise((resolve, reject) => {
    const tx = db.transaction(IDB_STORE, 'readwrite');
    const store = tx.objectStore(IDB_STORE);
    const req = store.delete(key);
    req.onsuccess = () => resolve();
    req.onerror = () => reject(req.error);
  });
}

export function useIndexedDB(key: string) {
  const dbRef = useRef<IDBDatabase | null>(null);
  const [stored, setStored] = useState<string | null>(null);
  const [ready, setReady] = useState(false);

  useEffect(() => {
    let cancelled = false;
    setReady(false);
    setStored(null);
    openDB()
      .then(db => {
        if (cancelled) { db.close(); return; }
        dbRef.current = db;
        return idbGet(db, key);
      })
      .then(val => {
        if (!cancelled) {
          setStored(val ?? null);
          setReady(true);
        }
      })
      .catch(() => {
        if (!cancelled) setReady(true);
      });
    return () => {
      cancelled = true;
      if (dbRef.current) { dbRef.current.close(); dbRef.current = null; }
    };
  }, [key]);

  const save = useCallback(
    (value: string) => {
      setStored(value);
      if (dbRef.current) idbPut(dbRef.current, key, value).catch(() => {});
    },
    [key],
  );

  const remove = useCallback(() => {
    setStored(null);
    if (dbRef.current) idbDelete(dbRef.current, key).catch(() => {});
  }, [key]);

  return { stored, save, remove, ready };
}

