import React, { useCallback, useEffect, useState } from 'react';
import { addons, types } from 'storybook/internal/manager-api';
import { IconButton } from 'storybook/internal/components';
import { themes } from '@storybook/theming';

const ADDON_ID = 'sb-dark-mode-toggle';
const TOOL_ID = `${ADDON_ID}/tool`;

function getInitialDark(): boolean {
  const stored = localStorage.getItem('sb-ui-theme');
  if (stored) return stored === 'dark';
  return window.matchMedia?.('(prefers-color-scheme: dark)').matches ?? false;
}

function DarkModeToggle() {
  const [isDark, setIsDark] = useState(getInitialDark);

  const toggle = useCallback(() => {
    const next = !isDark;
    setIsDark(next);
    localStorage.setItem('sb-ui-theme', next ? 'dark' : 'light');
    addons.setConfig({ theme: next ? themes.dark : themes.normal });
    window.location.reload();
  }, [isDark]);

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.shiftKey && e.key === 'D') {
        e.preventDefault();
        toggle();
      }
    };
    document.addEventListener('keydown', handler);
    return () => document.removeEventListener('keydown', handler);
  }, [toggle]);

  return (
    <IconButton
      key={TOOL_ID}
      title={`Switch to ${isDark ? 'light' : 'dark'} mode (⌘⇧D)`}
      onClick={toggle}
    >
      <span style={{ fontSize: 14, lineHeight: 1 }}>
        {isDark ? '☀️' : '🌙'}
      </span>
    </IconButton>
  );
}

addons.register(ADDON_ID, () => {
  addons.add(TOOL_ID, {
    type: types.TOOL,
    title: 'Dark mode',
    render: () => <DarkModeToggle />,
  });
});

